import pandas as pd
import numpy as np

def load_partition(i):
    # 1M rows x 10 floats => ~80MB each
    return pd.DataFrame(np.random.rand(1_000_000, 10), columns=[f'c{j}' for j in range(10)])

def build():
    frames = [load_partition(i) for i in range(200)]  # 16GB+ total
    # BUG: building one giant frame in-memory
    big = pd.concat(frames, ignore_index=True, copy=False)
    return big.mean()

if __name__ == '__main__':
    print(build())
